<script setup lang="ts">
import{ref}from'vue';import{onShow}from'@dcloudio/uni-app';import{patientApi}from'../../api/patient';import{session,saveSession,switchPatient,type PatientInfo}from'../../stores/session'
const patients=ref<PatientInfo[]>([]),loading=ref(false)
function maskPhone(phone?:string){return phone?phone.replace(/(\d{3})\d{4}(\d{4})/,'$1****$2'):'未填写手机号'}
function back(){uni.navigateBack({fail:()=>uni.redirectTo({url:'/pages/profile/index'})})}
async function load(){if(!session.userId)return;loading.value=true;try{patients.value=await patientApi.list(session.userId);saveSession({patients:patients.value})}finally{loading.value=false}}
function open(item?:PatientInfo){uni.navigateTo({url:item?`/pages/patient-form/index?id=${item.patientId}`:'/pages/patient-form/index'})}
function choose(item:PatientInfo){if(session.currentPatientId===item.patientId)return;switchPatient(item.patientId);uni.showToast({title:`已切换为 ${item.realName}`,icon:'success'})}
onShow(load)
</script>
<template><view class="patients-page"><view class="hero"><view class="back" @tap="back">‹</view><view class="hero-copy"><text>就诊人管理</text><text>管理本人及家庭就诊信息</text></view><image src="/static/patient/management-hero.svg" mode="aspectFit"/></view><view class="content"><view class="notice"><text>i</text><text>就诊人信息将用于挂号、缴费和病历查询，请确保真实准确。</text></view><view v-if="loading" class="state">正在加载就诊人…</view><view v-for="(item,index) in patients" :key="item.patientId" class="patient-card" :class="{current:session.currentPatientId===item.patientId}"><view class="avatar" :class="{family:index%2===1}">{{item.realName.slice(0,1)}}</view><view class="patient-info"><view class="name-row"><text>{{item.realName}}</text><text>{{item.relation||'家属'}}</text><text v-if="item.isPrimary===1">默认</text></view><text class="phone">{{maskPhone(item.phone)}}</text><view class="verified"><text>✓</text><text>已实名认证</text></view></view><view class="patient-actions"><button v-if="session.currentPatientId!==item.patientId" size="mini" @tap="choose(item)">切换</button><view v-else class="current-label"><text>✓</text><text>当前</text></view><view class="edit" @tap="open(item)"><text>编辑</text><text>›</text></view></view></view><view v-if="!loading&&!patients.length" class="state">暂无就诊人信息</view><view class="add-card" @tap="open()"><view>+</view><text>添加就诊人</text><text>可添加家人、朋友等就诊人</text></view><view class="tip-card"><view class="bell">♦</view><view><text>温馨提示</text><text>未成年人和老年人可以由家庭作为管理，身份信息与证件保持一致。</text></view><image src="/static/patient/tip-card.svg" mode="aspectFit"/></view></view><view class="wave"><view/><view/></view></view></template>
