x}.name-row{display:flex;align-items:center;gap:10rpx}.name-row text:first-child{font-size:29rpx;font-weight:650}.name-row text:not(:first-child){padding:5rpx 10rpx;border-radius:12rpx;background:#e9f3ff;color:#2878ff;font-size:16rpx}.name-row text:last-child:not(:nth-child(2)){background:#f0f3f7;color:#78869a}.phone{display:block;margin-top:8rpx;color:#73829a;font-size:21rpx}.verified{margin-top:9rpx;display:flex;align-items:center;gap:7rpx;color:#12aa7e;font-size:18rpx}.verified text:first-child{width:23rpx;height:23rpx;border-radius:7rpx;background:#16be8c;color:#fff;text-align:center;line-height:23rpx}.edit{display:flex;align-items:center;gap:8rpx;color:#2878ff;font-size:21rpx}.edit text:last-child{font-size:35rpx}.add-card{height:150rpx;margin-top:27rpx;display:flex;flex-direction:column;align-items:center;justify-content:center;border:2rpx dashed #8fc0ff;border-radius:23rpx;background:rgba(255,255,255,.5)}.add-card>view{position:absolute;margin-right:170rpx;margin-bottom:49rpx;width:34rpx;height:34rpx;border-radius:50%;background:#2f83f6;color:#fff;font-size:30rpx;text-align:center;line-height:31rpx}.add-card>text:nth-child(2){color:#2878f5;font-size:27rpx;font-weight:600}.add-card>text:last-child{margin-top:12rpx;color:#8390a5;font-size:19rpx}.tip-card{position:relative;min-height:145rpx;margin-top:27rpx;padding:27rpx 155rpx 27rpx 25rpx;box-sizing:border-box;display:flex;align-items:flex-start;gap:18rpx;border:1rpx solid #e8eff8;border-radius:24rpx;background:#fff;box-shadow:0 9rpx 25rpx rgba(41,88,150,.06)}.bell{width:58rpx;height:58rpx;flex:none;border-radius:19rpx;display:flex;align-items:center;justify-content:center;background:#eaf3ff;color:#2878ff;font-size:27rpx}.tip-card>view:nth-child(2){display:flex;flex-direction:column}.tip-card>view:nth-child(2) text:first-child{font-size:25rpx;font-weight:650}.tip-card>view:nth-child(2) text:last-child{width:330rpx;margin-top:9rpx;color:#75849b;font-size:18rpx;line-height:1.55}.tip-card>image{position:absolute;right:8rpx;bottom:3rpx;width:155rpx;height:120rpx}.state{margin-top:20rpx;padding:60rpx 20rpx;border-radius:24rpx;background:#fff;text-align:center;color:#8b97aa;font-size:21rpx}.wave{position:absolute;left:-10%;right:-10%;bottom:-50rpx;height:140rpx;opacity:.18}.wave view{height:80rpx;border-top:3rpx solid #65aaff;border-radius:50%;transform:rotate(5deg)}.wave view:last-child{transform:rotate(-4deg)}</style>
